/// <summary>
/// Classe-base das condições de desactivação de um inimigo (Enemy Creator —
/// infra-estrutura preparada na Etapa 1.6, populada na Etapa 5.4 com condições
/// baseadas em variáveis globais — ver GameVariables).
///
/// Cada subclasse [System.Serializable] implementa <see cref="Evaluate"/> e
/// aparece automaticamente no botão "+ Adicionar Condição de Desactivação" do
/// Inspector do EnemyController (via PolymorphicListDrawer — ver
/// EnemyControllerEditor).
/// </summary>
[System.Serializable]
public abstract class EnemyCondition
{
    /// <summary>Devolve true se a condição está cumprida (o inimigo deve passar a Desactivado).</summary>
    public abstract bool Evaluate(EnemyController enemy);
}
